import React, { useEffect, useState } from 'react';
import { api } from '../utils/api';
import VaccinModal from '../components/VaccinModal';
import OrdonnanceModal from '../components/OrdonnanceModal';
import algeriaData from '../data/algeria.json';

// ─── Utilitaire : impression dossier patient ──────────────────────────────────
function printDossierPatient(patient) {
  const age = patient.dateNaissance
    ? Math.floor((Date.now() - new Date(patient.dateNaissance)) / (1000 * 60 * 60 * 24 * 365.25))
    : '?';
  const html = `<!DOCTYPE html>
<html lang="fr"><head>
<meta charset="UTF-8"/>
<title>Dossier Patient – ${patient.prenom} ${patient.nom}</title>
<style>
  @import url('https://fonts.googleapis.com/css2?family=Syne:wght@700;800&family=DM+Sans:wght@400;500;600;700&display=swap');
  * { margin:0; padding:0; box-sizing:border-box; }
  body { font-family:'DM Sans',sans-serif; color:#1d2129; background:#fff; }
  .page { width:210mm; min-height:297mm; padding:18mm 22mm; margin:0 auto; }
  .header { display:flex; justify-content:space-between; align-items:flex-start; border-bottom:3px solid #0056ff; padding-bottom:14px; margin-bottom:22px; }
  .header-brand h1 { font-family:'Syne',sans-serif; color:#0056ff; font-size:22px; font-weight:800; }
  .header-brand p { color:#8a94a6; font-size:11px; margin-top:3px; }
  .header-meta { text-align:right; font-size:11px; color:#8a94a6; }
  .header-meta strong { display:block; color:#1d2129; font-size:13px; }
  .avatar-row { display:flex; align-items:center; gap:20px; background:#f4f7fe; border-radius:12px; padding:18px 22px; margin-bottom:22px; }
  .avatar { width:64px; height:64px; border-radius:50%; background:${patient.sexe === 'M' ? '#ebf2ff' : '#fce7f3'}; color:${patient.sexe === 'M' ? '#0056ff' : '#ec4899'}; display:flex; align-items:center; justify-content:center; font-family:'Syne',sans-serif; font-size:22px; font-weight:800; flex-shrink:0; }
  .avatar-info h2 { font-family:'Syne',sans-serif; font-size:20px; font-weight:800; }
  .avatar-info .id { font-family:monospace; font-size:11px; color:#8a94a6; margin-top:2px; }
  .avatar-info .tags { display:flex; gap:8px; margin-top:8px; flex-wrap:wrap; }
  .tag { padding:3px 12px; border-radius:50px; font-size:11px; font-weight:700; }
  .tag-blue { background:#ebf2ff; color:#0056ff; }
  .tag-pink { background:#fce7f3; color:#ec4899; }
  .tag-gray { background:#f4f5f9; color:#1d2129; }
  .tag-red { background:#fee2e2; color:#dc2626; }
  .section { margin-bottom:20px; }
  .section-title { font-family:'Syne',sans-serif; font-size:11px; font-weight:800; color:#0056ff; text-transform:uppercase; letter-spacing:1px; margin-bottom:10px; padding-bottom:5px; border-bottom:1px solid #eaebef; }
  .info-grid { display:grid; grid-template-columns:1fr 1fr; gap:12px 24px; }
  .info-item label { font-size:10px; font-weight:700; color:#8a94a6; text-transform:uppercase; letter-spacing:0.5px; display:block; margin-bottom:3px; }
  .info-item span { font-size:13px; font-weight:600; color:#1d2129; }
  .info-item.full { grid-column:span 2; }
  .footer { margin-top:40px; border-top:1px solid #eaebef; padding-top:16px; display:flex; justify-content:space-between; font-size:10px; color:#8a94a6; }
  .sign-box { text-align:center; }
  .sign-line { width:160px; border-top:1px solid #1d2129; margin:44px auto 6px; }
  @media print { .page { padding:12mm 18mm; } }
</style>
</head><body>
<div class="page">
  <div class="header">
    <div class="header-brand">
      <h1>🏥 DOSSIER PATIENT</h1>
      <p>Système de Vaccination — SEMEP / VacciTrack</p>
    </div>
    <div class="header-meta">
      <strong>Imprimé le ${new Date().toLocaleDateString('fr-FR', { day:'2-digit', month:'long', year:'numeric' })}</strong>
      Document officiel — confidentiel
    </div>
  </div>

  <div class="avatar-row">
    <div class="avatar">${patient.prenom[0]}${patient.nom[0]}</div>
    <div class="avatar-info">
      <h2>${patient.prenom} ${patient.nom}</h2>
      <div class="id">N° Dossier : ${patient.id}</div>
      <div class="tags">
        <span class="tag ${patient.sexe === 'M' ? 'tag-blue' : 'tag-pink'}">${patient.sexe === 'M' ? '♂ Masculin' : '♀ Féminin'}</span>
        <span class="tag tag-gray">${age} ans</span>
        ${patient.groupeSanguin ? `<span class="tag tag-red">🩸 ${patient.groupeSanguin}</span>` : ''}
        ${patient.poids ? `<span class="tag tag-gray">⚖ ${patient.poids} Kg</span>` : ''}
      </div>
    </div>
  </div>

  <div class="section">
    <div class="section-title">📋 Informations Personnelles</div>
    <div class="info-grid">
      <div class="info-item">
        <label>Prénom</label><span>${patient.prenom}</span>
      </div>
      <div class="info-item">
        <label>Nom</label><span>${patient.nom}</span>
      </div>
      <div class="info-item">
        <label>Date de naissance</label><span>${patient.dateNaissance ? new Date(patient.dateNaissance).toLocaleDateString('fr-FR') : '—'}</span>
      </div>
      <div class="info-item">
        <label>Âge</label><span>${age} ans</span>
      </div>
      <div class="info-item">
        <label>Sexe</label><span>${patient.sexe === 'M' ? 'Masculin' : 'Féminin'}</span>
      </div>
      <div class="info-item">
        <label>Groupe sanguin</label><span>${patient.groupeSanguin || '—'}</span>
      </div>
      <div class="info-item">
        <label>Poids</label><span>${patient.poids ? patient.poids + ' Kg' : '—'}</span>
      </div>
    </div>
  </div>

  <div class="section">
    <div class="section-title">📞 Contact</div>
    <div class="info-grid">
      <div class="info-item">
        <label>Téléphone</label><span>${patient.telephone || '—'}</span>
      </div>
      <div class="info-item">
        <label>Email</label><span>${patient.email || '—'}</span>
      </div>
      <div class="info-item full">
        <label>Adresse</label><span>${patient.adresse || [patient.commune, patient.daira, patient.wilaya].filter(Boolean).join(', ') || '—'}</span>
      </div>
    </div>
  </div>

  <div class="section">
    <div class="section-title">💼 Situation Professionnelle</div>
    <div class="info-grid">
      <div class="info-item">
        <label>Fonction</label><span>${patient.fonction || '—'}</span>
      </div>
      <div class="info-item">
        <label>Service</label><span>${patient.service || '—'}</span>
      </div>
      <div class="info-item">
        <label>Profession</label><span>${patient.profession || '—'}</span>
      </div>
      <div class="info-item">
        <label>Niveau d'instruction</label><span>${patient.instruction || '—'}</span>
      </div>
    </div>
  </div>

  <div class="footer">
    <div>VacciTrack — Système de Gestion Vaccinale | Document généré automatiquement</div>
    <div class="sign-box">
      <div class="sign-line"></div>
      <div>Visa du responsable médical</div>
    </div>
  </div>
</div>
<script>window.onload = () => { window.print(); window.onafterprint = () => window.close(); }</script>
</body></html>`;
  const w = window.open('', '_blank', 'width=900,height=750');
  w.document.write(html);
  w.document.close();
}

// ─── Utilitaire : impression dossier vaccinal ────────────────────────────────
async function printDossierVaccinal(patient) {
  let vaccinations = [];
  try {
    vaccinations = await api.getVaccinations({ patientId: patient.id });
  } catch {}

  const age = patient.dateNaissance
    ? Math.floor((Date.now() - new Date(patient.dateNaissance)) / (1000 * 60 * 60 * 24 * 365.25))
    : '?';

  const rows = vaccinations.map((v, i) => {
    const typeLabel = v.type === 'rage' ? 'Anti-Rabique' : v.type === 'hepb' ? 'Hépatite B' : v.type === 'dt' ? 'DT' : v.vaccin || '—';
    const details = v.type === 'rage' ? `Grade: ${v.protocoleData?.grade || '—'}` : v.type === 'hepb' ? `Schéma: ${v.protocoleData?.schema || '—'}` : 'Formulaire Officiel';
    const erig = v.protocoleData?.erig ? '✓ ERIG/SAR' : '';
    return `<tr>
      <td style="font-weight:700; color:#0056ff;">${i + 1}</td>
      <td>${new Date(v.createdAt).toLocaleDateString('fr-FR')}</td>
      <td><strong>${typeLabel}</strong></td>
      <td>${v.dose || '—'}</td>
      <td>${details}</td>
      <td>${v.dateProchaineDose ? new Date(v.dateProchaineDose).toLocaleDateString('fr-FR') : '—'}</td>
      <td style="color:#22c55e;">${erig}</td>
    </tr>`;
  }).join('');

  const html = `<!DOCTYPE html>
<html lang="fr"><head>
<meta charset="UTF-8"/>
<title>Carnet Vaccinal – ${patient.prenom} ${patient.nom}</title>
<style>
  @import url('https://fonts.googleapis.com/css2?family=Syne:wght@700;800&family=DM+Sans:wght@400;500;600;700&display=swap');
  * { margin:0; padding:0; box-sizing:border-box; }
  body { font-family:'DM Sans',sans-serif; color:#1d2129; background:#fff; }
  .page { width:210mm; min-height:297mm; padding:16mm 20mm; margin:0 auto; }
  .header { display:flex; justify-content:space-between; align-items:flex-start; border-bottom:3px solid #0056ff; padding-bottom:12px; margin-bottom:18px; }
  .header-brand h1 { font-family:'Syne',sans-serif; color:#0056ff; font-size:20px; font-weight:800; }
  .header-brand p { color:#8a94a6; font-size:11px; margin-top:2px; }
  .patient-banner { display:flex; justify-content:space-between; align-items:center; background:#f4f7fe; border-radius:12px; padding:14px 20px; margin-bottom:20px; border-left:4px solid #0056ff; }
  .patient-banner h2 { font-family:'Syne',sans-serif; font-size:17px; font-weight:800; }
  .patient-banner p { font-size:12px; color:#8a94a6; margin-top:2px; }
  .info-chips { display:flex; gap:8px; flex-wrap:wrap; margin-top:6px; }
  .chip { padding:2px 10px; border-radius:50px; font-size:11px; font-weight:700; background:#ebf2ff; color:#0056ff; }
  .chip.red { background:#fee2e2; color:#dc2626; }
  .section-title { font-family:'Syne',sans-serif; font-size:11px; font-weight:800; color:#0056ff; text-transform:uppercase; letter-spacing:1px; margin-bottom:10px; padding-bottom:4px; border-bottom:1px solid #eaebef; }
  table { width:100%; border-collapse:collapse; font-size:12px; }
  thead tr { background:#0056ff; color:white; }
  th { padding:8px 10px; text-align:left; font-weight:700; font-size:10px; text-transform:uppercase; letter-spacing:0.5px; }
  td { padding:10px; border-bottom:1px solid #eaebef; vertical-align:top; }
  tbody tr:nth-child(even) { background:#f9fafb; }
  .empty { text-align:center; padding:32px; color:#8a94a6; font-style:italic; }
  .footer { margin-top:30px; border-top:1px solid #eaebef; padding-top:12px; display:flex; justify-content:space-between; align-items:flex-end; font-size:10px; color:#8a94a6; }
  .sign-box { text-align:center; }
  .sign-line { width:160px; border-top:1px solid #1d2129; margin:44px auto 4px; }
  .summary-box { display:flex; gap:16px; margin-bottom:20px; }
  .summary-card { flex:1; border:1px solid #eaebef; border-radius:8px; padding:12px; text-align:center; }
  .summary-card .num { font-family:'Syne',sans-serif; font-size:24px; font-weight:800; color:#0056ff; }
  .summary-card .lbl { font-size:11px; color:#8a94a6; margin-top:2px; }
  @media print { .page { padding:10mm 15mm; } }
</style>
</head><body>
<div class="page">
  <div class="header">
    <div class="header-brand">
      <h1>💉 CARNET VACCINAL OFFICIEL</h1>
      <p>Service de Médecine Préventive — SEMEP / VacciTrack</p>
    </div>
    <div style="text-align:right; font-size:11px; color:#8a94a6;">
      <strong style="display:block; color:#1d2129; font-size:13px;">Imprimé le ${new Date().toLocaleDateString('fr-FR', { day:'2-digit', month:'long', year:'numeric' })}</strong>
      Document officiel — confidentiel
    </div>
  </div>

  <div class="patient-banner">
    <div>
      <h2>${patient.prenom} ${patient.nom}</h2>
      <p>N° Dossier : ${patient.id}</p>
      <div class="info-chips">
        <span class="chip">${patient.sexe === 'M' ? '♂ Masculin' : '♀ Féminin'}</span>
        <span class="chip">${age} ans</span>
        ${patient.groupeSanguin ? `<span class="chip red">🩸 ${patient.groupeSanguin}</span>` : ''}
        ${patient.telephone ? `<span class="chip">📞 ${patient.telephone}</span>` : ''}
      </div>
    </div>
    <div style="text-align:right; font-size:11px; color:#8a94a6;">
      <div>Née le : ${patient.dateNaissance ? new Date(patient.dateNaissance).toLocaleDateString('fr-FR') : '—'}</div>
      <div>Adresse : ${patient.adresse || '—'}</div>
    </div>
  </div>

  <div class="summary-box">
    <div class="summary-card">
      <div class="num">${vaccinations.length}</div>
      <div class="lbl">Certificats enregistrés</div>
    </div>
    <div class="summary-card">
      <div class="num">${vaccinations.filter(v => v.type === 'rage').length}</div>
      <div class="lbl">Anti-Rabique</div>
    </div>
    <div class="summary-card">
      <div class="num">${vaccinations.filter(v => v.type === 'hepb').length}</div>
      <div class="lbl">Hépatite B</div>
    </div>
    <div class="summary-card">
      <div class="num">${vaccinations.filter(v => v.type === 'dt').length}</div>
      <div class="lbl">DT</div>
    </div>
  </div>

  <div class="section-title">💉 Historique des Vaccinations</div>
  ${vaccinations.length === 0
    ? '<div class="empty">Aucun vaccin enregistré pour ce patient.</div>'
    : `<table>
    <thead>
      <tr>
        <th>#</th>
        <th>Date</th>
        <th>Type de Vaccin</th>
        <th>Dose</th>
        <th>Détails</th>
        <th>Prochaine Dose</th>
        <th>Sérum</th>
      </tr>
    </thead>
    <tbody>${rows}</tbody>
  </table>`}

  <div class="footer">
    <div>VacciTrack — Système de Gestion Vaccinale | Document généré automatiquement</div>
    <div class="sign-box">
      <div class="sign-line"></div>
      <div>Visa du responsable médical</div>
    </div>
  </div>
</div>
<script>window.onload = () => { window.print(); window.onafterprint = () => window.close(); }</script>
</body></html>`;

  const w = window.open('', '_blank', 'width=950,height=750');
  w.document.write(html);
  w.document.close();
}



const EMPTY = {
  nom: '', prenom: '', dateNaissance: '', sexe: 'M',
  telephone: '', email: '', 
  wilaya: '', daira: '', commune: '', adressePrecise: '',
  groupeSanguin: 'A+', poids: '', fonction: '', service: '',
  profession: '', instruction: ''
};


const GROUPES = ['A+', 'A-', 'B+', 'B-', 'AB+', 'AB-', 'O+', 'O-'];

function PatientModal({ patient, onClose, onSave }) {
  const [form, setForm] = useState(patient || EMPTY);
  const [age, setAge] = useState('');

  const wilayas = algeriaData.wilayas;
  const selectedWilaya = wilayas.find(w => w.name === form.wilaya);
  const dairas = selectedWilaya?.dairas || [];
  const selectedDaira = dairas.find(d => d.name === form.daira);
  const communes = selectedDaira?.communes || [];

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  // Calcul automatique de l'âge
  useEffect(() => {
    if (form.dateNaissance) {
      const birthDate = new Date(form.dateNaissance);
      const today = new Date();
      let calculatedAge = today.getFullYear() - birthDate.getFullYear();
      const m = today.getMonth() - birthDate.getMonth();
      if (m < 0 || (m === 0 && today.getDate() < birthDate.getDate())) {
        calculatedAge--;
      }
      setAge(calculatedAge >= 0 ? `${calculatedAge} ans` : '');
    } else {
      setAge('');
    }
  }, [form.dateNaissance]);

  const handleSubmit = async (e) => {
    e.preventDefault();

    // Génération de l'ID structuré pour un nouveau patient
    // Format: DOB(YYYYMMDD)-RegDate(YYYYMMDD)-RAND
    if (!patient?.id) {
      const dob = form.dateNaissance.replace(/-/g, '');
      const today = new Date().toISOString().slice(0, 10).replace(/-/g, '');
      const rand = Math.floor(Math.random() * 1000).toString().padStart(3, '0');
      form.id = `${dob}-${today}-${rand}`;

      // Stockage de l'adresse concaténée pour la compatibilité affichage
      form.adresse = `${form.commune}, ${form.daira}, ${form.wilaya} (${form.adressePrecise})`;
    }

    if (patient?.id) {
      await api.updatePatient(patient.id, form);
    } else {
      await api.createPatient(form);
    }
    onSave();
  };

  return (
    <div style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(29, 33, 41, 0.4)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000 }} onClick={e => e.target === e.currentTarget && onClose()}>
