                          </button>

                          {/* VOIR VACCINATIONS */}
                          <button onClick={() => { setSelectedPatient(p); setPage('vaccinations'); }} style={{ background: '#ebf2ff', border: '1px solid #d4e3ff', borderRadius: '8px', padding: '8px', cursor: 'pointer', color: '#0056ff' }} title="Voir le profil vaccinal (Historique)">
                            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"></path><circle cx="12" cy="12" r="3"></circle></svg>
                          </button>

                          {/* SUPPRIMER */}
                          <button onClick={() => handleDelete(p.id)} style={{ background: '#fce7f3', border: '1px solid #fbcfe8', borderRadius: '8px', padding: '8px', cursor: 'pointer', color: '#ec4899' }} title="Supprimer ce dossier">
                            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path></svg>
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {modal && (
        <PatientModal
          patient={modal === 'create' ? null : modal}
          onClose={() => setModal(null)}
          onSave={() => { setModal(null); load(); }}
        />
      )}

      {ordonnancePatient && (
        <OrdonnanceModal
          patient={ordonnancePatient}
          onClose={() => setOrdonnancePatient(null)}
        />
      )}

      {vaccinModalPatientId && (
        <VaccinModal
          initialPatientId={vaccinModalPatientId}
          patients={patients}
          onClose={() => setVaccinModalPatientId(null)}
          onSave={() => { setVaccinModalPatientId(null); setPage('vaccinations'); }}
        />
      )}
    </div>
  );
}
